import{d as e,k as t,m as n,t as r}from"./chunks/plugin-vue_export-helper.DVGAxL5v.js";var i=JSON.parse(`{"title":"LMCache：推理缓存系统","description":"介绍 LMCache 如何通过跨请求 KV Cache 共享与多级缓存调度机制降低 LLM 推理成本并优化响应延迟。","frontmatter":{"title":"LMCache：推理缓存系统","description":"介绍 LMCache 如何通过跨请求 KV Cache 共享与多级缓存调度机制降低 LLM 推理成本并优化响应延迟。"},"headers":[],"relativePath":"inference/optimization/lmcache.md","filePath":"inference/optimization/lmcache.md","lastUpdated":1782721961000}`),a={name:`inference/optimization/lmcache.md`};function o(r,i,a,o,s,c){return t(),e(`div`,null,[...i[0]||=[n(`<h1 id="lmcache-推理缓存系统" tabindex="-1">LMCache：推理缓存系统 <a class="header-anchor" href="#lmcache-推理缓存系统" aria-label="Permalink to “LMCache：推理缓存系统”">​</a></h1><p>在当前 AI 生态中，LLM 推理已成为核心基础设施。然而，随着上下文长度和请求复杂度的持续增长，推理成本与延迟压力急剧上升。LMCache 通过精准的 KV Cache 调度与跨请求共享机制，显著降低推理成本并优化响应延迟。</p><h2 id="_1-核心思想-每段文本只需读取一次" tabindex="-1">1. 核心思想：每段文本只需读取一次 <a class="header-anchor" href="#_1-核心思想-每段文本只需读取一次" aria-label="Permalink to “1. 核心思想：每段文本只需读取一次”">​</a></h2><p>LMCache 的核心理念是：<strong>每一段文本，模型只需读取一次</strong>。在真实应用中，大量数据被重复访问——热门文档、历史对话、检索片段等。根据帕累托法则，20% 的内容可能贡献 80% 的访问。LMCache 将所有可复用文本的 KV Cache 统一存储，当后续请求再次引用时直接复用，无需重新计算，无论这些内容出现在请求前缀还是中间位置。</p><p>该方案由芝加哥大学开发，已与 vLLM 等引擎集成。实测显示，在多轮问答、RAG 等场景中，TTFT 可提升 3–10 倍，同时有效节省 GPU 计算资源。</p><h2 id="_2-三大关键特性" tabindex="-1">2. 三大关键特性 <a class="header-anchor" href="#_2-三大关键特性" aria-label="Permalink to “2. 三大关键特性”">​</a></h2><h3 id="_2-1-海量规模-massive-scale" tabindex="-1">2.1 海量规模（Massive Scale） <a class="header-anchor" href="#_2-1-海量规模-massive-scale" aria-label="Permalink to “2.1 海量规模（Massive Scale）”">​</a></h3><p>LMCache 支持存储远超 GPU 显存容量的大规模 KV Cache 数据，通过解耦模型推理与上下文存储，使大模型可以应对更长上下文、更多用户并发。</p><h3 id="_2-2-极速加载-blazing-speed" tabindex="-1">2.2 极速加载（Blazing Speed） <a class="header-anchor" href="#_2-2-极速加载-blazing-speed" aria-label="Permalink to “2.2 极速加载（Blazing Speed）”">​</a></h3><p>LMCache 基于 CUDA 加速算子与流水线数据传输，可将命中的 KV Cache 以极低延迟加载到 GPU 显存，显著降低 TTFT。</p><h3 id="_2-3-插件式存储后端-pluggable-storage" tabindex="-1">2.3 插件式存储后端（Pluggable Storage） <a class="header-anchor" href="#_2-3-插件式存储后端-pluggable-storage" aria-label="Permalink to “2.3 插件式存储后端（Pluggable Storage）”">​</a></h3><p>LMCache 提供开放接口，可集成 MooncakeStore、Infinistore、Redis、分布式文件系统（DFS）等多种后端，适配不同企业部署需求。</p><p>借助上述能力，LMCache 扩展了 vLLM 分页内存机制的有效边界，使推理引擎可以跨请求复用历史上下文缓存，不再受限于单次会话的显存分配策略。</p><h2 id="_3-工作原理" tabindex="-1">3. 工作原理 <a class="header-anchor" href="#_3-工作原理" aria-label="Permalink to “3. 工作原理”">​</a></h2><p>TTFT 受限于 Prefill 阶段，需要将输入上下文编码为 KV Cache 后才能开始生成。LMCache 将 Prefill 阶段计算得到的 KV Cache 缓存起来，下次遇到相同上下文时直接复用，从而大幅降低 TTFT。</p><p>LMCache 支持将 KV Cache 存储到内存、磁盘、Redis、GDS、NIXL 等多种后端，详情参阅 <a href="https://docs.lmcache.ai/kv_cache/storage_backends/index.html" target="_blank" rel="noreferrer">存储后端文档</a>。</p><p>此外，LMCache 提供了 <a href="https://lmcache.ai/kv_cache_calculator.html" target="_blank" rel="noreferrer">KV Cache 大小计算工具</a>。以 4K 中文文本估算，2K Token 约需 106 MB 的 KV Cache，存储开销非常大。因此生产环境通常需要配合大容量存储后端（如 Redis、3FS、大容量磁盘）。</p><h2 id="_4-快速上手-缓存到内存" tabindex="-1">4. 快速上手：缓存到内存 <a class="header-anchor" href="#_4-快速上手-缓存到内存" aria-label="Permalink to “4. 快速上手：缓存到内存”">​</a></h2><h3 id="环境变量配置" tabindex="-1">环境变量配置 <a class="header-anchor" href="#环境变量配置" aria-label="Permalink to “环境变量配置”">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 启用 LMCache V1 实验性功能</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">export</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> LMCACHE_USE_EXPERIMENTAL</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">True</span></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 每个 KV Chunk 包含 256 个 Token</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">export</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> LMCACHE_CHUNK_SIZE</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;">256</span></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 启用 CPU 内存后端</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">export</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> LMCACHE_LOCAL_CPU</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">True</span></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 分配 50 GB 固定 CPU 内存</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">export</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> LMCACHE_MAX_LOCAL_CPU_SIZE</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;">50</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="启动-vllm-服务" tabindex="-1">启动 vLLM 服务 <a class="header-anchor" href="#启动-vllm-服务" aria-label="Permalink to “启动 vLLM 服务”">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">export</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> CUDA_VISIBLE_DEVICES</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;">7</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">vllm</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> serve</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> /data/models/Qwen2.5-7B-Instruct</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;"> \\</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">    --no-enable-prefix-caching</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;"> \\</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">    --max-model-len</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;"> 16384</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;"> \\</span></span>
<span class="line"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">    --kv-transfer-config</span><span style="--shiki-light:#EE0000;--shiki-dark:#D7BA7D;"> \\</span></span>
<span class="line"><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">    &#39;{&quot;kv_connector&quot;:&quot;LMCacheConnectorV1&quot;, &quot;kv_role&quot;:&quot;kv_both&quot;}&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="_5-超越推理引擎-llm-原生编排层" tabindex="-1">5. 超越推理引擎：LLM 原生编排层 <a class="header-anchor" href="#_5-超越推理引擎-llm-原生编排层" aria-label="Permalink to “5. 超越推理引擎：LLM 原生编排层”">​</a></h2><p>除缓存技术外，LMCache 团队还提出了面向 LLM 推理的<strong>原生编排层（LLM-Native Orchestration）</strong> 愿景。当前业界几乎将全部注意力集中在推理引擎内部优化（如 vLLM、SGLang、TensorRT-LLM），却忽视了引擎之上、跨引擎的系统级优化空间。</p><h3 id="_5-1-现状-以引擎为中心的扩展" tabindex="-1">5.1 现状：以引擎为中心的扩展 <a class="header-anchor" href="#_5-1-现状-以引擎为中心的扩展" aria-label="Permalink to “5.1 现状：以引擎为中心的扩展”">​</a></h3><p>当前大模型推理系统主要由两部分构成：</p><ul><li><strong>推理引擎</strong>：针对单个模型实例优化推理性能。</li><li><strong>编排层</strong>：借助 Kubernetes 等工具水平复制引擎实例。</li></ul><p>这种思维假定性能增益主要来自引擎内部，编排层只是无状态的“薄壳”。驱动该模型的开源系统包括：</p><ul><li><a href="https://github.com/vllm-project/production-stack" target="_blank" rel="noreferrer">vLLM Production Stack</a></li><li><a href="https://github.com/llm-d/llm-d" target="_blank" rel="noreferrer">llm-d</a> 与 <a href="https://kserve.github.io/website/0.15/blog/articles/2025-05-27-KServe-0.15-release/" target="_blank" rel="noreferrer">KServe</a></li><li><a href="https://github.com/ai-dynamo/dynamo" target="_blank" rel="noreferrer">NVIDIA Dynamo</a></li><li><a href="https://github.com/vllm-project/aibrix" target="_blank" rel="noreferrer">ByteDance AIBrix</a></li><li><a href="https://github.com/modular/modular" target="_blank" rel="noreferrer">Modular</a></li><li><a href="https://github.com/sgl-project/ome" target="_blank" rel="noreferrer">SGLang OME</a></li></ul><p>这些方案在横向扩展上表现良好，但难以实现更深层次的系统级优化。</p><h3 id="_5-2-新前沿-跨引擎的全局优化" tabindex="-1">5.2 新前沿：跨引擎的全局优化 <a class="header-anchor" href="#_5-2-新前沿-跨引擎的全局优化" aria-label="Permalink to “5.2 新前沿：跨引擎的全局优化”">​</a></h3><p>真正的性能提升来自“跨引擎”的智能编排，例如：</p><ul><li>动态 Prefill / Decode 分离</li><li>跨会话的 KV Cache 共享、传输与压缩</li><li>在线 KV Cache 更新（融合、编辑、翻译）</li><li>请求路径外的后台计算</li><li>查询迁移与跨 Agent 流水线</li></ul><p>这些优化需要“有状态的协同”与“智能调度”，而原生 Kubernetes 方案很难直接提供。</p><h3 id="_5-3-kubernetes-的局限性" tabindex="-1">5.3 Kubernetes 的局限性 <a class="header-anchor" href="#_5-3-kubernetes-的局限性" aria-label="Permalink to “5.3 Kubernetes 的局限性”">​</a></h3><p>Kubernetes 仍是现代基础设施的核心，但仅靠它做 LLM 推理编排会限制上限：</p><ul><li><strong>仅支持无状态副本</strong>：LLM 工作负载依赖共享的 KV Cache 与中间工具调用状态，而 Kubernetes 原生不支持请求与副本间的状态共享。</li><li><strong>仅支持请求驱动执行</strong>：缓存压缩、后台预取、后台融合等优化需要在关键路径外运行，Kubernetes 的基于请求-响应的调度模型难以支撑。</li><li><strong>不适合 LLM 特有逻辑</strong>：推理专用调度（如延迟敏感型任务优先）用 Go/Rust 实现的原型效率较低。</li><li><strong>运维复杂度高</strong>：相比 OpenAI、Fireworks 等托管服务，基于 Kubernetes 的推理栈部署和运维难度更高。</li></ul><h3 id="_5-4-llm-原生编排器的需求" tabindex="-1">5.4 LLM 原生编排器的需求 <a class="header-anchor" href="#_5-4-llm-原生编排器的需求" aria-label="Permalink to “5.4 LLM 原生编排器的需求”">​</a></h3><p>下一代推理编排器应具备：</p><ul><li>面向张量的通信与状态共享能力（用于 KV Cache 复用、迁移与流水线）</li><li>可中断的后台任务（用于压缩、融合及非请求类计算）</li><li>感知延迟、资源占用与依赖关系的实时 / 后台任务调度</li><li>易于部署与运维，即使团队缺乏深厚基础设施经验</li></ul><p>这不是取代 Kubernetes，而是对其补充：Kubernetes 负责容器生命周期、节点扩缩与集群管理，而 LLM 原生编排器负责理解 LLM 特有模式。</p><h2 id="_6-总结" tabindex="-1">6. 总结 <a class="header-anchor" href="#_6-总结" aria-label="Permalink to “6. 总结”">​</a></h2><p>LMCache 不仅在缓存算法上突破了前缀匹配限制、支持多级存储与跨引擎共享，还从系统架构层面提出了 LLM 原生编排的演进方向。对于希望降低长上下文推理成本、提升 TTFT 的团队，LMCache 是一个低成本高潜力的切入点。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to “参考”">​</a></h2><ul><li><a href="https://github.com/LMCache/LMCache" target="_blank" rel="noreferrer">LMCache GitHub</a></li><li><a href="https://docs.lmcache.ai/" target="_blank" rel="noreferrer">LMCache 文档</a></li></ul>`,45)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};